","const PREPR_TABLE = "x_1339198_sap_pr_0_prepr";
const LINE_ITEM_TABLE = "x_1339198_sap_pr_0_line_item";

const headers = () => ({
 Accept: "application/json",
 "Content-Type": "application/json",
 "X-UserToken": (window as any).g_ck
});

export async function fetchPrePRList() {
 const res = await fetch(
 `/api/now/table/${PREPR_TABLE}?sysparm_display_value=all&sysparm_limit=50&sysparm_orderby=sys_created_on`,
 { headers: headers() }
 );
 const data = await res.json();
 return data.result || [];
}

export async function fetchPrePR(sysId: string) {
 const res = await fetch(
 `/api/now/table/${PREPR_TABLE}/${sysId}?sysparm_display_value=all`,
 { headers: headers() }
 );
 const data = await res.json();
 return data.result;
}

export async function createPrePR(record: any) {
 const res = await fetch(
 `/api/now/table/${PREPR_TABLE}?sysparm_display_value=all`,
 { method: "POST", headers: headers(), body: JSON.stringify(record) }
 );
 const data = await res.json();
 return data.result;
}

export async function updatePrePR(sysId: string, record: any) {
 const res = await fetch(
 `/api/now/table/${PREPR_TABLE}/${sysId}?sysparm_display_value=all`,
 { method: "PATCH", headers: headers(), body: JSON.stringify(record) }
 );
 const data = await res.json();
 return data.result;
}

export async function fetchLineItems(preprId: string) {
 const res = await fetch(
 `/api/now/table/${LINE_ITEM_TABLE}?sysparm_display_value=all&sysparm_query=prepr=${preprId}&sysparm_orderby=item_number`,
 { headers: headers() }
 );
 const data = await res.json();
 return data.result || [];
}

export async function createLineItem(record: any) {
 const res = await fetch(
 `/api/now/table/${LINE_ITEM_TABLE}?sysparm_display_value=all`,
 { method: "POST", headers: headers(), body: JSON.stringify(record) }
 );
 const data = await res.json();
 return data.result;
}

export async function updateLineItem(sysId: string, record: any) {
 const res = await fetch(
 `/api/now/table/${LINE_ITEM_TABLE}/${sysId}?sysparm_display_value=all`,
 { method: "PATCH", headers: headers(), body: JSON.stringify(record) }
 );
 const data = await res.json();
 return data.result;
}

export async function deleteLineItem(sysId: string) {
 await fetch(`/api/now/table/${LINE_ITEM_TABLE}/${sysId}`, {
 method: "DELETE",
 headers: headers()
 });
}
