","import React from "react";
import { Button } from "@servicenow/react-components/Button";

interface LineItem {
 sys_id?: string;
 item_number: string;
 description: string;
 delivery_date: string;
 plant: string;
 quantity: string;
 unit_measure: string;
 unit_price: string;
 valuation_price: string;
 material_group: string;
 purchase_group: string;
 service_code: string;
 service_quantity: string;
 cost_center: string;
 account_category: string;
 item_type: string;
}

const EMPTY_ITEM: LineItem = {
 item_number: "", description: "", delivery_date: "", plant: "",
 quantity: "", unit_measure: "", unit_price: "", valuation_price: "",
 material_group: "", purchase_group: "", service_code: "",
 service_quantity: "", cost_center: "", account_category: "", item_type: ""
};

const UOM_OPTIONS = [
 ["", ""], ["ea", "EA"], ["kg", "KG"], ["l", "L"], ["m", "M"],
 ["pc", "PC"], ["hr", "HR"], ["day", "DAY"], ["box", "BOX"],
 ["set", "SET"], ["ton", "TON"]
];

interface Props {
 items: LineItem[];
 onChange: (items: LineItem[]) => void;
}

export default function LineItemTable({ items, onChange }: Props) {
 function addItem() {
 const nextNum = String(items.length + 1);
 onChange([...items, { ...EMPTY_ITEM, item_number: nextNum }]);
 }

 function removeItem(index: number) {
 onChange(items.filter((_, i) => i !== index));
 }

 function updateItem(index: number, field: string, val: string) {
 const updated = items.map((item, i) =>
 i === index ? { ...item, [field]: val } : item
 );
 onChange(updated);
 }

 return (
 <div>
 <table className="line-items-table">
 <thead>
 <tr>
 <th>#</th>
 <th>Description *</th>
 <th>Qty *</th>
 <th>UoM</th>
 <th>Unit Price *</th>
 <th>Plant</th>
 <th>Delivery Date</th>
 <th>Material Grp</th>
 <th>Service Code</th>
 <th>Cost Center</th>
 <th></th>
 </tr>
 </thead>
 <tbody>
 {items.map((item, idx) => (
 <tr key={idx}>
 <td>{item.item_number || idx + 1}</td>
 <td><input value={item.description} onChange={(e) => updateItem(idx, "description", e.target.value)} placeholder="Item description" /></td>
 <td><input type="number" value={item.quantity} onChange={(e) => updateItem(idx, "quantity", e.target.value)} style={{ width: 70 }} /></td>
 <td>
 <select value={item.unit_measure} onChange={(e) => updateItem(idx, "unit_measure", e.target.value)}>
 {UOM_OPTIONS.map(([v, l]) => <option key={v} value={v}>{l}</option>)}
 </select>
 </td>
 <td><input type="number" value={item.unit_price} onChange={(e) => updateItem(idx, "unit_price", e.target.value)} style={{ width: 90 }} /></td>
 <td><input value={item.plant} onChange={(e) => updateItem(idx, "plant", e.target.value)} style={{ width: 70 }} /></td>
 <td><input type="date" value={item.delivery_date} onChange={(e) => updateItem(idx, "delivery_date", e.target.value)} /></td>
 <td><input value={item.material_group} onChange={(e) => updateItem(idx, "material_group", e.target.value)} style={{ width: 90 }} /></td>
 <td><input value={item.service_code} onChange={(e) => updateItem(idx, "service_code", e.target.value)} style={{ width: 80 }} /></td>
 <td><input value={item.cost_center} onChange={(e) => updateItem(idx, "cost_center", e.target.value)} style={{ width: 80 }} /></td>
 <td><Button label="Remove" variant="destructive" size="sm" onClicked={() => removeItem(idx)} /></td>
 </tr>
 ))}
 </tbody>
 </table>
 <div className="btn-actions">
 <Button label="+ Add Line Item" variant="secondary" onClicked={addItem} />
 </div>
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { Button } from "@servicenow/react-components/Button";
import { createPrePR, updatePrePR, fetchPrePR, fetchLineItems, createLineItem, updateLineItem, deleteLineItem } from "../services/preprService";
import { value } from "../utils/fields";
import LineItemTable from "./LineItemTable";

interface Props {
 id?: string;
 onBack: () => void;
 onSaved: (id: string) => void;
}

const EMPTY_FORM = {
 title: "", account_category: "", item_type: "", comments: "",
 pl_comments: "", material_group: "", purchase_group: "",
 cost_center: "", plant: ""
};

export default function PrePRForm({ id, onBack, onSaved }: Props) {
 const [form, setForm] = useState(EMPTY_FORM);
 const [lineItems, setLineItems] = useState<any[]>([]);
 const [saving, setSaving] = useState(false);
 const isEdit = !!id;

 useEffect(() => {
 if (id) {
 fetchPrePR(id).then((r) => {
 setForm({
 title: value(r.title), account_category: value(r.account_category),
 item_type: value(r.item_type), comments: value(r.comments),
 pl_comments: value(r.pl_comments), material_group: value(r.material_group),
 purchase_group: value(r.purchase_group), cost_center: value(r.cost_center),
 plant: value(r.plant)
 });
 });
 fetchLineItems(id).then((items) => {
 setLineItems(items.map((i: any) => ({
 sys_id: value(i.sys_id), item_number: value(i.item_number),
 description: value(i.description), delivery_date: value(i.delivery_date),
 plant: value(i.plant), quantity: value(i.quantity),
 unit_measure: value(i.unit_measure), unit_price: value(i.unit_price),
 valuation_price: value(i.valuation_price), material_group: value(i.material_group),
 purchase_group: value(i.purchase_group), service_code: value(i.service_code),
 service_quantity: value(i.service_quantity), cost_center: value(i.cost_center),
 account_category: value(i.account_category), item_type: value(i.item_type)
 })));
 });
 }
 }, [id]);

 function handleChange(field: string, val: string) {
 setForm((prev) => ({ ...prev, [field]: val }));
 }

 async function handleSave() {
 setSaving(true);
 try {
 let preprId = id;
 if (isEdit) {
 await updatePrePR(id!, form);
 } else {
 const result = await createPrePR({ ...form, status: "draft" });
 preprId = value(result.sys_id);
 }
 await saveLineItems(preprId!);
 onSaved(preprId!);
 } finally {
 setSaving(false);
 }
 }

 async function saveLineItems(preprId: string) {
 for (const item of lineItems) {
 const payload = { ...item, prepr: preprId };
 delete payload.sys_id;
 if (item.sys_id) {
 await updateLineItem(item.sys_id, payload);
 } else {
 await createLineItem(payload);
 }
 }
 }

 async function handleSubmitForApproval() {
 setSaving(true);
 try {
 let preprId = id;
 if (isEdit) {
 await updatePrePR(id!, { ...form, status: "pending_approval" });
 } else {
 const result = await createPrePR({ ...form, status: "pending_approval" });
 preprId = value(result.sys_id);
 }
 await saveLineItems(preprId!);
 onSaved(preprId!);
 } finally {
 setSaving(false);
 }
 }

 return (
 <div className="prepr-app">
 <div className="prepr-header">
 <h1>{isEdit ? "Edit PrePR Request" : "New PrePR Request"}</h1>
 <Button label="Cancel" variant="secondary" onClicked={onBack} />
 </div>
 <div className="prepr-section">
 <h2>Request Information</h2>
 <div className="form-grid">
 <FormInput label="Title *" value={form.title} onChange={(v) => handleChange("title", v)} />
 <FormSelect label="Account Category" value={form.account_category} onChange={(v) => handleChange("account_category", v)}
 options={[["", "-- None --"], ["asset", "Asset"], ["cost_center_acct", "Cost Center"], ["order", "Order"], ["project", "Project"]]} />
 <FormSelect label="Item Type" value={form.item_type} onChange={(v) => handleChange("item_type", v)}
 options={[["", "-- None --"], ["material", "Material"], ["service", "Service"], ["subcontracting", "Subcontracting"], ["third_party", "Third Party"]]} />
 <FormInput label="Material Group" value={form.material_group} onChange={(v) => handleChange("material_group", v)} />
 <FormInput label="Purchase Group" value={form.purchase_group} onChange={(v) => handleChange("purchase_group", v)} />
 <FormInput label="Cost Center" value={form.cost_center} onChange={(v) => handleChange("cost_center", v)} />
 <FormInput label="Plant" value={form.plant} onChange={(v) => handleChange("plant", v)} />
 <FormTextarea label="Comments" value={form.comments} onChange={(v) => handleChange("comments", v)} />
 <FormTextarea label="P&L Comments" value={form.pl_comments} onChange={(v) => handleChange("pl_comments", v)} />
 </div>
 </div>
 <div className="prepr-section">
 <h2>Line Items</h2>
 <LineItemTable items={lineItems} onChange={setLineItems} />
 </div>
 <div className="btn-actions">
 <Button label={saving ? "Saving..." : "Save as Draft"} variant="secondary" onClicked={handleSave} disabled={saving || !form.title} />
 <Button label="Submit for Approval" variant="primary" onClicked={handleSubmitForApproval} disabled={saving || !form.title || lineItems.length === 0} />
 </div>
 </div>
 );
}

function FormInput({ label, value: val, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
 return (
 <div className="form-field">
 <label>{label}</label>
 <input value={val} onChange={(e) => onChange(e.target.value)} />
 </div>
 );
}

function FormSelect({ label, value: val, onChange, options }: { label: string; value: string; onChange: (v: string) => void; options: string[][] }) {
 return (
 <div className="form-field">
 <label>{label}</label>
 <select value={val} onChange={(e) => onChange(e.target.value)}>
 {options.map(([v, l]) => <option key={v} value={v}>{l}</option>)}
 </select>
 </div>
 );
}

function FormTextarea({ label, value: val, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
 return (
 <div className="form-field form-field-full">
 <label>{label}</label>
 <textarea rows={3} value={val} onChange={(e) => onChange(e.target.value)} />
 </div>
 );
}
","import React, { useEffect, useState } from "react";
import { Button } from "@servicenow/react-components/Button";
import { fetchPrePR, fetchLineItems } from "../services/preprService";
import { display, value } from "../utils/fields";

interface Props {
 id: string;
 onBack: () => void;
 onEdit: (id: string) => void;
}

export default function PrePRDetail({ id, onBack, onEdit }: Props) {
 const [prepr, setPrepr] = useState<any>(null);
 const [items, setItems] = useState<any[]>([]);

 useEffect(() => {
 fetchPrePR(id).then(setPrepr);
 fetchLineItems(id).then(setItems);
 }, [id]);

 if (!prepr) return <div className="prepr-app">Loading...</div>;

 return (
 <div className="prepr-app">
 <div className="prepr-header">
 <h1>{display(prepr.title)} - {display(prepr.number)}</h1>
 <div className="btn-actions">
 <Button label="Back" variant="secondary" onClicked={onBack} />
 <Button label="Edit" variant="primary" onClicked={() => onEdit(id)} />
 </div>
 </div>
 <div className="prepr-section">
 <h2>Request Details</h2>
 <div className="form-grid">
 <DetailField label="Status" value={display(prepr.status)} status={value(prepr.status)} />
 <DetailField label="PR Number" value={display(prepr.pr_number)} />
 <DetailField label="Account Category" value={display(prepr.account_category)} />
 <DetailField label="Item Type" value={display(prepr.item_type)} />
 <DetailField label="Material Group" value={display(prepr.material_group)} />
 <DetailField label="Purchase Group" value={display(prepr.purchase_group)} />
 <DetailField label="Cost Center" value={display(prepr.cost_center)} />
 <DetailField label="Plant" value={display(prepr.plant)} />
 <DetailField label="Progress" value={display(prepr.progress)} />
 <DetailField label="Requested By" value={display(prepr.requested_by)} />
 <DetailField label="Total Value" value={display(prepr.total_value)} />
 </div>
 </div>
 {display(prepr.comments) && (
 <div className="prepr-section">
 <h2>Comments</h2>
 <p>{display(prepr.comments)}</p>
 </div>
 )}
 {display(prepr.pl_comments) && (
 <div className="prepr-section">
 <h2>P&amp;L Comments</h2>
 <p>{display(prepr.pl_comments)}</p>
 </div>
 )}
 <div className="prepr-section">
 <h2>Line Items ({items.length})</h2>
 <table className="line-items-table">
 <thead>
 <tr>
 <th>#</th>
 <th>Description</th>
 <th>Qty</th>
 <th>UoM</th>
 <th>Unit Price</th>
 <th>Total</th>
 <th>Material Group</th>
 <th>Delivery Date</th>
 </tr>
 </thead>
 <tbody>
 {items.map((item) => (
 <tr key={value(item.sys_id)}>
 <td>{display(item.item_number)}</td>
 <td>{display(item.description)}</td>
 <td>{display(item.quantity)}</td>
 <td>{display(item.unit_measure)}</td>
 <td>{display(item.unit_price)}</td>
 <td>{display(item.total_price)}</td>
 <td>{display(item.material_group)}</td>
 <td>{display(item.delivery_date)}</td>
 </tr>
 ))}
 {items.length === 0 && (
 <tr><td colSpan={8}>No line items added.</td></tr>
 )}
 </tbody>
 </table>
 </div>
 </div>
 );
}

function DetailField({ label, value: val, status }: { label: string; value: string; status?: string }) {
 return (
 <div className="form-field">
 <label>{label}</label>
 {status ? (
 <span className={`status-badge status-${status}`}>{val || "—"}</span>
 ) : (
 <span>{val || "—"}</span>
 )}
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import PrePRList from "./components/PrePRList";
import PrePRForm from "./components/PrePRForm";
import PrePRDetail from "./components/PrePRDetail";
import "./app.css";

function getView() {
 const params = new URLSearchParams(window.location.search);
 return {
 view: params.get("view") || "list",
 id: params.get("id") || null
 };
}

export default function App() {
 const [route, setRoute] = useState(getView());

 useEffect(() => {
 const handlePop = () => setRoute(getView());
 window.addEventListener("popstate", handlePop);
 return () => window.removeEventListener("popstate", handlePop);
 }, []);

 function navigate(view: string, id?: string | null) {
 const params = new URLSearchParams();
 params.set("view", view);
 if (id) params.set("id", id);
 const path = `${window.location.pathname}?${params.toString()}`;
 if (window.self !== window.top) {
 (window as any).CustomEvent.fireTop("magellanNavigator.permalink.set", {
 relativePath: path,
 title: "SAP PrePR"
 });
 } else {
 window.history.pushState({}, "", path);
 }
 setRoute({ view, id: id || null });
 }

 if (route.view === "create") {
 return <PrePRForm onBack={() => navigate("list")} onSaved={(id) => navigate("detail", id)} />;
 }
 if (route.view === "detail" && route.id) {
 return <PrePRDetail id={route.id} onBack={() => navigate("list")} onEdit={(id) => navigate("edit", id)} />;
 }
 if (route.view === "edit" && route.id) {
 return <PrePRForm id={route.id} onBack={() => navigate("detail", route.id)} onSaved={(id) => navigate("detail", id)} />;
 }
 return <PrePRList onNew={() => navigate("create")} onSelect={(id) => navigate("detail", id)} />;
}
",".prepr-app {
 max-width: 1200px;
 margin: 0 auto;
 padding: 24px;
 font-family: var(--now-font-family, "Lato", sans-serif);
}

.prepr-header {
 display: flex;
 justify-content: space-between;
 align-items: center;
 margin-bottom: 24px;
}

.prepr-header h1 {
 margin: 0;
 font-size: 24px;
 color: rgb(var(--now-color--neutral-21, 22, 27, 33));
}

.prepr-section {
 margin-bottom: 24px;
 padding: 16px;
 border: 1px solid rgb(var(--now-color--neutral-5, 218, 220, 224));
 border-radius: 4px;
 background: rgb(var(--now-color--background-primary, 255, 255, 255));
}

.prepr-section h2 {
 margin: 0 0 16px 0;
 font-size: 18px;
 color: rgb(var(--now-color--neutral-18, 66, 80, 92));
}

.form-grid {
 display: grid;
 grid-template-columns: 1fr 1fr;
 gap: 16px;
}

.form-field {
 display: flex;
 flex-direction: column;
 gap: 4px;
}

.form-field label {
 font-size: 12px;
 font-weight: 600;
 color: rgb(var(--now-color--neutral-15, 99, 114, 126));
}

.form-field-full {
 grid-column: 1 / -1;
}

.line-items-table {
 width: 100%;
 border-collapse: collapse;
 margin-top: 12px;
 font-size: 13px;
}

.line-items-table th {
 background: rgb(var(--now-color--neutral-3, 237, 238, 240));
 padding: 8px 10px;
 text-align: left;
 font-weight: 600;
 font-size: 11px;
 text-transform: uppercase;
 color: rgb(var(--now-color--neutral-15, 99, 114, 126));
 border-bottom: 1px solid rgb(var(--now-color--neutral-5, 218, 220, 224));
}

.line-items-table td {
 padding: 6px 10px;
 border-bottom: 1px solid rgb(var(--now-color--neutral-3, 237, 238, 240));
 vertical-align: middle;
}

.line-items-table input,
.line-items-table select {
 width: 100%;
 padding: 4px 6px;
 border: 1px solid rgb(var(--now-color--neutral-5, 218, 220, 224));
 border-radius: 2px;
 font-size: 13px;
}

.btn-actions {
 display: flex;
 gap: 8px;
 margin-top: 16px;
}

.status-badge {
 display: inline-block;
 padding: 2px 8px;
 border-radius: 12px;
 font-size: 12px;
 font-weight: 600;
}

.status-draft { background: rgb(var(--now-color--neutral-3, 237, 238, 240)); color: rgb(var(--now-color--neutral-15, 99, 114, 126)); }
.status-pending_approval { background: rgb(var(--now-color_selection--warning--2, 255, 240, 209)); color: rgb(var(--now-color--warning-2, 156, 106, 0)); }
.status-approved { background: rgb(var(--now-color_selection--positive--2, 212, 247, 226)); color: rgb(var(--now-color--positive-2, 0, 120, 62)); }
.status-rejected { background: rgb(var(--now-color_selection--critical--2, 255, 220, 220)); color: rgb(var(--now-color--critical-2, 180, 30, 30)); }
.status-submitted_to_sap { background: rgb(var(--now-color_selection--info--2, 210, 234, 255)); color: rgb(var(--now-color--secondary-1, 0, 100, 140)); }
.status-completed { background: rgb(var(--now-color_selection--positive--2, 212, 247, 226)); color: rgb(var(--now-color--positive-2, 0, 120, 62)); }
","export default function insertStyle(css, tagName = "style") {
 if (!css || typeof window === "undefined")
 return;
 if (tagName === "style") {
 const style = document.createElement("style");
 style.setAttribute("type", "text/css");
 style.innerHTML = css;
 document.head.appendChild(style);
 }
 else if (tagName === "link") {
 const link = document.createElement("link");
 link.setAttribute("rel", "stylesheet");
 link.setAttribute("href", css);
 document.head.appendChild(link);
 }
 return css;
}","import React from "react";
